/* Recursive let semantics: supports mutually recursive bindings */
public JamVal forLet(Let l) {

  /* Extract binding vars and exps (rhs's) from l */
  Variable[] vars = l.vars();
  AST[] exps = l.exps();
  int n = vars.length;

  /* Step 1: Create dummy bindings for each variable */
  PureList<Binding> newEnv = env();
  Binding[] dummyBindings = new Binding[n];
  for(int i = 0; i < n; i++) {
    dummyBindings[i] = bindingPolicy.newDummyBinding(vars[i]);
    newEnv = newEnv.cons(dummyBindings[i]);
  }

  /* Step 2: Create new EvalVisitor with extended environment containing dummy bindings */
  EvalVisitor newEV = newEvalVisitor(newEnv);

  /* Step 3: Evaluate each RHS in the new environment and update the corresponding binding */
  for(int i = 0; i < n; i++) {
    Suspension susp = new ConcreteSuspension(exps[i], newEV);
    dummyBindings[i].setBinding(susp);
  }

  return l.body().accept(newEV);
}

