/** Class for a lazy cons structure - call-by-name (re-evaluates on each access). */
static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;

  public JamLazyNameCons(Suspension fs, Suspension rs) {
    super(null, null);  // Initialize with null; will be set by overrides
    firstSusp = fs;
    restSusp = rs;
  }

  /** Override first() to force evaluation of firstSusp and cache result */
  @Override
  public JamVal first() {
    if (first == null) {
      first = firstSusp.eval();
    }
    return first;
  }

  /** Override rest() to force evaluation of restSusp and cache result */
  @Override
  public JamList rest() {
    if (rest == null) {
      JamVal restVal = restSusp.eval();
      rest = JamCons.checkList(restVal);
    }
    return (JamList) rest;
  }
}

