/** Class for a lazy cons with optimization - call-by-need (evaluates once and caches). */
static class JamLazyNeedCons extends JamLazyNameCons {
  /** Flag to track if first has been evaluated */
  private boolean firstEvaluated = false;
  /** Flag to track if rest has been evaluated */
  private boolean restEvaluated = false;

  public JamLazyNeedCons(Suspension fs, Suspension rs) {
    super(fs, rs);
  }

  /** Override first() to evaluate once and cache result */
  @Override
  public JamVal first() {
    if (!firstEvaluated) {
      first = firstSusp.eval();
      firstSusp = null;  // Release for GC
      firstEvaluated = true;
    }
    return first;
  }

  /** Override rest() to evaluate once and cache result */
  @Override
  public JamList rest() {
    if (!restEvaluated) {
      JamVal restVal = restSusp.eval();
      rest = JamCons.checkList(restVal);
      restSusp = null;  // Release for GC
      restEvaluated = true;
    }
    return (JamList) rest;
  }
}

