/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error,
  * throws a SyntaxException.
  */
class CheckVisitor implements ASTVisitor<Void> {

  /** Empty symbol table. */
  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();

  /** Symbol table to detect free variables. */
  PureList<Variable> env;

  /** Root form of CheckVisitor. */
  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);

  CheckVisitor(PureList<Variable> e) { env = e; }

  /* Helper method to create a new CheckVisitor with an extended environment. */
  private CheckVisitor newCheckVisitor(PureList<Variable> e) {
    return new CheckVisitor(e);
  }

  /* Helper method to check if a variable is in the environment. */
  private boolean isInEnv(Variable v) {
    return env.accept(new LookupVisitor<Variable>(v)) != null;
  }

  /* Helper method to check for duplicate variables in a list. */
  private void checkNoDuplicates(Variable[] vars, String context) {
    PureList<Variable> varList = new Empty<Variable>();
    for (int i = 0; i < vars.length; i++) {
      varList = varList.cons(vars[i]);
    }
    varList.accept(new AnyDuplicatesVisitor());
  }

  /* ASTVisitor methods. */
  public Void forBoolConstant(BoolConstant b) { return null; }
  public Void forIntConstant(IntConstant i) { return null; }
  public Void forEmptyConstant(EmptyConstant n) { return null; }

  public Void forVariable(Variable v) {
    if (!isInEnv(v)) {
      throw new SyntaxException("Variable " + v + " is not bound");
    }
    return null;
  }

  public Void forPrimFun(PrimFun f) { return null; }

  public Void forUnOpApp(UnOpApp u) {
    return u.arg().accept(this);
  }

  public Void forBinOpApp(BinOpApp b) {
    b.arg1().accept(this);
    return b.arg2().accept(this);
  }

  public Void forApp(App a) {
    a.rator().accept(this);
    AST[] args = a.args();
    for (int i = 0; i < args.length; i++) {
      args[i].accept(this);
    }
    return null;
  }

  public Void forMap(Map m) {
    Variable[] vars = m.vars();
    checkNoDuplicates(vars, "map parameters");

    // Create new environment with map parameters
    PureList<Variable> newEnv = env;
    for (int i = 0; i < vars.length; i++) {
      newEnv = newEnv.cons(vars[i]);
    }

    CheckVisitor newCV = newCheckVisitor(newEnv);
    return m.body().accept(newCV);
  }

  public Void forIf(If i) {
    i.test().accept(this);
    i.conseq().accept(this);
    return i.alt().accept(this);
  }

  public Void forLet(Let l) {
    Variable[] vars = l.vars();
    AST[] exps = l.exps();

    checkNoDuplicates(vars, "let bindings");

    // Create new environment with let-bound variables
    PureList<Variable> newEnv = env;
    for (int i = 0; i < vars.length; i++) {
      newEnv = newEnv.cons(vars[i]);
    }

    CheckVisitor newCV = newCheckVisitor(newEnv);

    // Check each RHS in the new environment (supports recursive let)
    for (int i = 0; i < exps.length; i++) {
      exps[i].accept(newCV);
    }

    // Check body in the new environment
    return l.body().accept(newCV);
  }
}

